import { useState, useEffect, useCallback, useRef } from 'react';
import { useDispatch } from 'react-redux';
import {
  setProjects,
  setLoading,
  setError,
  setGuestbookEntries,
  setGuestbookLoading,
  setGuestbookError,
  addGuestbookEntry,
  deleteGuestbookEntry,
  setVisitorCount,
  incrementVisitor,
} from '../store/store';

//žąėž†ēŪēīžēľŪē® ŪėĄ Ž°úžĽ¨Ž°ú ŽŹĆŽ¶¨Í≥† žěąžĚĆ
const API_BASE = 'http://localhost:3001';

// ============================================
// useProjects - ŪĒĄŽ°úž†ĚŪäł ŽćįžĚīŪĄį fetch (GET)
// async/await žā¨žö©
// ============================================
export function useProjects() {
  const dispatch = useDispatch();
  const [localLoading, setLocalLoading] = useState(true);

  const fetchProjects = useCallback(async () => {
    dispatch(setLoading(true));
    setLocalLoading(true);

    try {
      const response = await fetch(`${API_BASE}/projects`);

      if (!response.ok) {
        throw new Error('ŪĒĄŽ°úž†ĚŪäł ŽćįžĚīŪĄįŽ•ľ Ž∂ąŽü¨žė§ŽäĒŽćį žč§ŪĆ®ŪĖąžäĶŽčąŽč§.');
      }

      const data = await response.json();
      dispatch(setProjects(data));
    } catch (error) {
      dispatch(setError(error.message));
      console.error('Fetch projects error:', error);
    } finally {
      setLocalLoading(false);
    }
  }, [dispatch]);

  useEffect(() => {
    fetchProjects();
  }, [fetchProjects]);

  return { refetch: fetchProjects, loading: localLoading };
}

// ============================================
// useGuestbook - Žį©Ž™ÖŽ°Ě CRUD (GET, POST, DELETE)
// REST API + async/await Ūôúžö©
// ============================================
export function useGuestbook() {
  const dispatch = useDispatch();

  // READ - Žį©Ž™ÖŽ°Ě Ž™©Ž°Ě ž°įŪöĆ
  const fetchGuestbook = useCallback(async () => {
    dispatch(setGuestbookLoading(true));

    try {
      const response = await fetch(`${API_BASE}/guestbook?_sort=createdAt&_order=desc`);

      if (!response.ok) {
        throw new Error('Žį©Ž™ÖŽ°ĚžĚĄ Ž∂ąŽü¨žė§ŽäĒŽćį žč§ŪĆ®ŪĖąžäĶŽčąŽč§.');
      }

      const data = await response.json();
      dispatch(setGuestbookEntries(data));
    } catch (error) {
      dispatch(setGuestbookError(error.message));
      console.error('Fetch guestbook error:', error);
    }
  }, [dispatch]);

  // CREATE - žÉą Žį©Ž™ÖŽ°Ě žěĎžĄĪ (POST)
  const createEntry = useCallback(async (name, message) => {
    try {
      const newEntry = {
        name: name.trim() || 'žĚĶŽ™Ö',
        message: message.trim(),
        createdAt: new Date().toISOString(),
      };

      const response = await fetch(`${API_BASE}/guestbook`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newEntry),
      });

      if (!response.ok) {
        throw new Error('Žį©Ž™ÖŽ°Ě žěĎžĄĪžóź žč§ŪĆ®ŪĖąžäĶŽčąŽč§.');
      }

      const data = await response.json();
      dispatch(addGuestbookEntry(data));
      return { success: true, data };
    } catch (error) {
      console.error('Create guestbook entry error:', error);
      return { success: false, error: error.message };
    }
  }, [dispatch]);

  // DELETE - Žį©Ž™ÖŽ°Ě žā≠ž†ú
  const removeEntry = useCallback(async (id) => {
    try {
      const response = await fetch(`${API_BASE}/guestbook/${id}`, {
        method: 'DELETE',
      });

      if (!response.ok) {
        throw new Error('Žį©Ž™ÖŽ°Ě žā≠ž†úžóź žč§ŪĆ®ŪĖąžäĶŽčąŽč§.');
      }

      dispatch(deleteGuestbookEntry(id));
      return { success: true };
    } catch (error) {
      console.error('Delete guestbook entry error:', error);
      return { success: false, error: error.message };
    }
  }, [dispatch]);

  useEffect(() => {
    fetchGuestbook();
  }, [fetchGuestbook]);

  return { fetchGuestbook, createEntry, removeEntry };
}

// ============================================
// useVisitor - Žį©Ž¨łžěź žąė ÍīÄŽ¶¨
// ============================================
export function useVisitor() {
  const dispatch = useDispatch();

  const fetchAndIncrement = useCallback(async () => {
    try {
      // ŪėĄžě¨ Žį©Ž¨łžěź žąė ž°įŪöĆ
      const response = await fetch(`${API_BASE}/visitors`);
      const data = await response.json();

      const hasVisited = sessionStorage.getItem('hasVisited') === 'true';

      if (!hasVisited) {
        // Žį©Ž¨łžěź žąė ž¶ĚÍįÄ (PUT)
        const newCount = data.count + 1;
        await fetch(`${API_BASE}/visitors`, {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ count: newCount }),
        });

        dispatch(setVisitorCount(newCount));
        dispatch(incrementVisitor());
      } else {
        dispatch(setVisitorCount(data.count));
      }
    } catch (error) {
      console.error('Visitor count error:', error);
    }
  }, [dispatch]);

  useEffect(() => {
    fetchAndIncrement();
  }, [fetchAndIncrement]);
}

// ============================================
// useSkills - žä§Ūā¨ ŽćįžĚīŪĄį fetch
// ============================================
export function useSkills() {
  const [skills, setSkills] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchSkills = async () => {
      try {
        const response = await fetch(`${API_BASE}/skills`);
        const data = await response.json();
        setSkills(data);
      } catch (error) {
        console.error('Fetch skills error:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchSkills();
  }, []);

  return { skills, loading };
}

// ============================================
// useTimeline - ŪÉÄžěĄŽĚľžĚł ŽćįžĚīŪĄį fetch
// ============================================
export function useTimeline() {
  const [timeline, setTimeline] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTimeline = async () => {
      try {
        const response = await fetch(`${API_BASE}/timeline`);
        const data = await response.json();
        setTimeline(data);
      } catch (error) {
        console.error('Fetch timeline error:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchTimeline();
  }, []);

  return { timeline, loading };
}

// ============================================
// useScrollToSection - useRefŽ•ľ Ūôúžö©Ūēú žä§ŪĀ¨Ž°§ žĚīŽŹô
// ============================================
export function useScrollToSection() {
  const sectionRefs = useRef({});

  const registerSection = useCallback((name, ref) => {
    sectionRefs.current[name] = ref;
  }, []);

  const scrollToSection = useCallback((name) => {
    const section = sectionRefs.current[name];
    if (section) {
      section.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  }, []);

  return { registerSection, scrollToSection, sectionRefs };
}

// ============================================
// useIntersectionObserver - žä§ŪĀ¨Ž°§ ÍįźžßÄ (useRef Ūôúžö©)
// ============================================
export function useIntersectionObserver(options = {}) {
  const [isIntersecting, setIsIntersecting] = useState(false);
  const targetRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        setIsIntersecting(entry.isIntersecting);
      },
      { threshold: 0.1, ...options }
    );

    const currentTarget = targetRef.current;
    if (currentTarget) {
      observer.observe(currentTarget);
    }

    return () => {
      if (currentTarget) {
        observer.unobserve(currentTarget);
      }
    };
  }, [options]);

  return { targetRef, isIntersecting };
}
